import React, { useState } from 'react';
import { X, Mail, Lock, User } from 'lucide-react';
import { useAppContext } from '../context/AppContext';
import { API_BASE_URL } from '../utils/api';

const SignInModal = () => {
  const { state, dispatch } = useAppContext();
  const [isSignUp, setIsSignUp] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
  });

  const handleClose = () => {
    dispatch({ type: 'TOGGLE_SIGNIN', payload: false });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    (async () => {
      try {
        const url = `${API_BASE_URL}/api/auth/${isSignUp ? 'register' : 'login'}`;
        const body = isSignUp
          ? { email: formData.email, password: formData.password, name: formData.name }
          : { email: formData.email, password: formData.password };
        const res = await fetch(url, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(body),
        });
        const data = await res.json();
        if (!res.ok) {
          alert(data.error || 'Authentication failed');
          return;
        }
        // Save user in context
        dispatch({ type: 'SET_USER', payload: { id: data.user.id, email: data.user.email, name: data.user.name } });
        dispatch({ type: 'TOGGLE_SIGNIN', payload: false });
        setFormData({ name: '', email: '', password: '' });
      } catch (e) {
        alert('Authentication error');
      }
    })();
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  if (!state.isSignInOpen) return null;

  return (
    <div className="fixed inset-0 bg-luxury-dark/70 backdrop-blur-sm flex items-center justify-center z-50">
      <div className="glass-card-emerald border border-emerald-luxury/40 rounded-lg p-8 max-w-md w-full mx-4 shadow-glow-emerald">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold text-gold-primary luxury-serif">
            {isSignUp ? 'Create Account' : 'Sign In'}
          </h2>
          <button
            onClick={handleClose}
            className="text-platinum/60 hover:text-gold-primary transition-all duration-300"
          >
            <X className="h-6 w-6" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          {isSignUp && (
            <div>
              <label className="block text-sm font-medium text-platinum mb-2 luxury-serif">
                Full Name
              </label>
              <div className="relative">
                <User className="absolute left-3 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gold-primary/60" />
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleInputChange}
                  className="w-full pl-10 pr-4 py-3 bg-luxury-secondary border border-emerald-luxury/30 rounded-lg text-platinum placeholder-platinum/40 focus:ring-2 focus:ring-emerald-luxury/60 focus:border-transparent outline-none transition-all duration-300"
                  placeholder="Enter your full name"
                  required={isSignUp}
                />
              </div>
            </div>
          )}

          <div>
            <label className="block text-sm font-medium text-platinum mb-2 luxury-serif">
              Email Address
            </label>
            <div className="relative">
              <Mail className="absolute left-3 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gold-primary/60" />
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleInputChange}
                className="w-full pl-10 pr-4 py-3 bg-luxury-secondary border border-emerald-luxury/30 rounded-lg text-platinum placeholder-platinum/40 focus:ring-2 focus:ring-emerald-luxury/60 focus:border-transparent outline-none transition-all duration-300"
                placeholder="Enter your email"
                required
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-platinum mb-2 luxury-serif">
              Password
            </label>
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gold-primary/60" />
              <input
                type="password"
                name="password"
                value={formData.password}
                onChange={handleInputChange}
                className="w-full pl-10 pr-4 py-3 bg-luxury-secondary border border-emerald-luxury/30 rounded-lg text-platinum placeholder-platinum/40 focus:ring-2 focus:ring-emerald-luxury/60 focus:border-transparent outline-none transition-all duration-300"
                placeholder="Enter your password"
                required
              />
            </div>
          </div>

          <button
            type="submit"
            className="w-full btn-premium-gold text-luxury-dark py-3 px-6 rounded-lg font-medium hover:shadow-glow transition-all duration-300"
          >
            {isSignUp ? 'Create Account' : 'Sign In'}
          </button>
        </form>

        <div className="mt-6 text-center">
          <p className="text-sm text-platinum/70">
            {isSignUp ? 'Already have an account?' : "Don't have an account?"}
            <button
              onClick={() => setIsSignUp(!isSignUp)}
              className="ml-2 text-gold-primary hover:text-gold-highlight font-medium transition-colors duration-300"
            >
              {isSignUp ? 'Sign In' : 'Sign Up'}
            </button>
          </p>
        </div>
      </div>
    </div>
  );
};

export default SignInModal;

import React from 'react';
import { X, Heart, ShoppingBag } from 'lucide-react';
import { useAppContext } from '../context/AppContext';

interface WishlistProps {
  isOpen: boolean;
  onClose: () => void;
}

const Wishlist: React.FC<WishlistProps> = ({ isOpen, onClose }) => {
  const { state, dispatch } = useAppContext();

  const removeFromWishlist = (id: number) => {
    dispatch({ type: 'REMOVE_FROM_WISHLIST', payload: id });
  };

  const addToCart = (product: any) => {
    dispatch({ type: 'ADD_TO_CART', payload: product });
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-luxury-dark/70 backdrop-blur-sm flex items-center justify-center z-50">
      <div className="glass-card-ruby border border-ruby-luxury/40 rounded-lg max-w-2xl w-full mx-4 max-h-[80vh] overflow-hidden shadow-glow-ruby">
        <div className="flex items-center justify-between p-6 border-b border-ruby-luxury/30">
          <h2 className="text-2xl font-bold text-gold-primary luxury-serif">Wishlist</h2>
          <button
            onClick={onClose}
            className="text-platinum/60 hover:text-gold-primary transition-colors duration-300"
          >
            <X className="h-6 w-6" />
          </button>
        </div>

        <div className="p-6 overflow-y-auto max-h-96">
          {state.wishlist.length === 0 ? (
            <div className="text-center py-8">
              <Heart className="h-16 w-16 text-ruby-luxury/30 mx-auto mb-4" />
              <p className="text-platinum/70 text-lg">Your wishlist is empty</p>
              <button
                onClick={onClose}
                className="mt-4 btn-premium-gold text-luxury-dark px-6 py-2 rounded-lg hover:shadow-glow transition-all duration-300"
              >
                Continue Shopping
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {state.wishlist.map((item) => (
                <div key={item.id} className="glass-card-sapphire border border-sapphire-luxury/30 rounded-lg p-4 shadow-glow-sapphire">
                  <div className="relative mb-4">
                    <img
                      src={item.image}
                      alt={item.name}
                      className="w-full h-32 object-cover rounded-lg border border-gold-primary/30"
                    />
                    <button
                      onClick={() => removeFromWishlist(item.id)}
                      className="absolute top-2 right-2 p-1 bg-luxury-dark/50 rounded-full shadow-md hover:shadow-lg hover-ruby-glow transition-all"
                    >
                      <Heart className="h-4 w-4 text-ruby-luxury fill-current" />
                    </button>
                  </div>
                  <h3 className="font-medium text-platinum mb-2 luxury-serif">{item.name}</h3>
                  <div className="flex items-center justify-between mb-3">
                    <span className="text-gold-primary font-bold">
                      Rs. {item.price.toLocaleString()}.00
                    </span>
                    {item.originalPrice && (
                      <span className="text-sm text-platinum/50 line-through">
                        Rs. {item.originalPrice.toLocaleString()}.00
                      </span>
                    )}
                  </div>
                  <button
                    onClick={() => addToCart(item)}
                    className="w-full btn-premium-gold text-luxury-dark py-2 px-4 rounded-lg font-medium hover:shadow-glow transition-all duration-300 flex items-center justify-center space-x-2"
                  >
                    <ShoppingBag className="h-4 w-4" />
                    <span>Add to Cart</span>
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

